A basic event dispatcher pattern in C++ gameplay coding:

```cpp
#include <vector>

class IHealthListener {
public:
    virtual ~IHealthListener() {}
    virtual void OnHealthChanged(float NewHealth) = 0;
};

class UCharacterStats {
private:
    std::vector<IHealthListener*> Listeners;
    float Health = 100.0f;

public:
    void RegisterListener(IHealthListener* Listener) {
        Listeners.push_back(Listener);
    }

    void ApplyDamage(float Amt) {
        Health -= Amt;
        for (auto* L : Listeners) {
            L->OnHealthChanged(Health); // Triggers updates decoupling concrete UI or Audio
        }
    }
};
```
